import 'dart:async';import 'dart:convert';import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'package:http/http.dart' as http;import 'reset_password_page.dart';import 'app_text.dart';class OTPPage extends StatefulWidget {  final String email;  const OTPPage({super.key, required this.email});  @override  State<OTPPage> createState() => _OTPPageState();}class _OTPPageState extends State<OTPPage> with TickerProviderStateMixin {  final List<TextEditingController> _controllers =  List.generate(6, (_) => TextEditingController());  final List<FocusNode> _focusNodes =  List.generate(6, (_) => FocusNode());  bool loading = false;  bool _shakeError = false;  static const String backendBase = "http://192.168.1.6:4000";  int seconds = 30;  bool canResend = false;  Timer? _timer;  late AnimationController _fadeCtrl;  late AnimationController _slideCtrl;  late AnimationController _shakeCtrl;  late AnimationController _pulseCtrl;  late Animation<double> _fadeAnim;  late Animation<Offset> _slideAnim;  late Animation<double> _shakeAnim;  late Animation<double> _pulseAnim;  @override  void initState() {    super.initState();    _fadeCtrl = AnimationController(vsync: this, duration: const Duration(milliseconds: 800));    _slideCtrl = AnimationController(vsync: this, duration: const Duration(milliseconds: 700));    _shakeCtrl = AnimationController(vsync: this, duration: const Duration(milliseconds: 500));    _pulseCtrl = AnimationController(vsync: this, duration: const Duration(milliseconds: 1500))      ..repeat(reverse: true);    _fadeAnim = CurvedAnimation(parent: _fadeCtrl, curve: Curves.easeOut);    _slideAnim = Tween<Offset>(begin: const Offset(0, 0.18), end: Offset.zero)        .animate(CurvedAnimation(parent: _slideCtrl, curve: Curves.easeOutCubic));    _shakeAnim = Tween<double>(begin: 0, end: 1).animate(_shakeCtrl);    _pulseAnim = Tween<double>(begin: 0.85, end: 1.0)        .animate(CurvedAnimation(parent: _pulseCtrl, curve: Curves.easeInOut));    _fadeCtrl.forward();    _slideCtrl.forward();    startTimer();  }  @override  void dispose() {    for (final c in _controllers) c.dispose();    for (final f in _focusNodes) f.dispose();    _timer?.cancel();    _fadeCtrl.dispose();    _slideCtrl.dispose();    _shakeCtrl.dispose();    _pulseCtrl.dispose();    super.dispose();  }  /* ── TIMER ── */  void startTimer() {    setState(() { seconds = 30; canResend = false; });    _timer?.cancel();    _timer = Timer.periodic(const Duration(seconds: 1), (t) {      if (seconds == 0) {        t.cancel();        if (mounted) setState(() => canResend = true);      } else {        if (mounted) setState(() => seconds--);      }    });  }  /* ── OTP VALUE ── */  String get _otpValue => _controllers.map((c) => c.text).join();  /* ── VERIFY ── */  Future<void> verifyOTP() async {    if (_otpValue.length < 6) {      _triggerShake();      _toast(AppText.t("enterOtp"));      return;    }    setState(() => loading = true);    HapticFeedback.lightImpact();    try {      final res = await http.post(        Uri.parse("$backendBase/api/auth/verify-otp"),        headers: {"Content-Type": "application/json"},        body: jsonEncode({"email": widget.email, "otp": _otpValue}),      );      final data = jsonDecode(res.body);      if (!mounted) return;      if (res.statusCode == 200) {        HapticFeedback.mediumImpact();        Navigator.pushReplacement(          context,          MaterialPageRoute(            builder: (_) => ResetPasswordPage(email: widget.email),          ),        );      } else {        _triggerShake();        _toast(data["msg"] ?? AppText.t("invalidOtp"));      }    } catch (_) {      _toast(AppText.t("networkError"));    }    if (mounted) setState(() => loading = false);  }  /* ── RESEND ── */  Future<void> resendOTP() async {    if (!canResend) return;    HapticFeedback.selectionClick();    try {      final res = await http.post(        Uri.parse("$backendBase/api/auth/forgot-password"),        headers: {"Content-Type": "application/json"},        body: jsonEncode({"email": widget.email}),      );      if (!mounted) return;      if (res.statusCode == 200) {        for (final c in _controllers) c.clear();        _focusNodes[0].requestFocus();        _toast(AppText.t("otpSentAgain"));        startTimer();      } else {        _toast(AppText.t("otpFailed"));      }    } catch (_) {      _toast(AppText.t("networkError"));    }  }  void _triggerShake() {    setState(() => _shakeError = true);    _shakeCtrl.forward(from: 0).then((_) {      if (mounted) setState(() => _shakeError = false);    });  }  void _toast(String msg) {    ScaffoldMessenger.of(context).hideCurrentSnackBar();    ScaffoldMessenger.of(context).showSnackBar(      SnackBar(        content: Text(msg, style: const TextStyle(color: Colors.white, fontWeight: FontWeight.w500)),        backgroundColor: const Color(0xFF1C1C2E),        behavior: SnackBarBehavior.floating,        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),        margin: const EdgeInsets.fromLTRB(16, 0, 16, 16),      ),    );  }  /* ── OTP INPUT FIELD LOGIC ── */  void _onChanged(int index, String value) {    if (value.length > 1) {      // handle paste      final paste = value.replaceAll(RegExp(r'\D'), '');      for (int i = 0; i < 6; i++) {        _controllers[i].text = i < paste.length ? paste[i] : '';      }      FocusScope.of(context).unfocus();      return;    }    if (value.isNotEmpty && index < 5) {      _focusNodes[index + 1].requestFocus();    }    setState(() {});  }  void _onKeyPress(int index, RawKeyEvent event) {    if (event is RawKeyDownEvent &&        event.logicalKey == LogicalKeyboardKey.backspace &&        _controllers[index].text.isEmpty &&        index > 0) {      _focusNodes[index - 1].requestFocus();      _controllers[index - 1].clear();      setState(() {});    }  }  /* ── BUILD ── */  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: const Color(0xFF0E0E1A),      body: Stack(        children: [          _backgroundDecor(),          SafeArea(            child: FadeTransition(              opacity: _fadeAnim,              child: SlideTransition(                position: _slideAnim,                child: Column(                  children: [                    _topBar(),                    Expanded(                      child: SingleChildScrollView(                        padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 8),                        child: Column(                          children: [                            const SizedBox(height: 24),                            _headerSection(),                            const SizedBox(height: 48),                            _otpInputRow(),                            const SizedBox(height: 32),                            _resendSection(),                            const SizedBox(height: 40),                            _verifyButton(),                            const SizedBox(height: 32),                          ],                        ),                      ),                    ),                  ],                ),              ),            ),          ),        ],      ),    );  }  /* ── BACKGROUND ── */  Widget _backgroundDecor() {    return Stack(      children: [        // Top-left glow        Positioned(          top: -80,          left: -60,          child: Container(            width: 280,            height: 280,            decoration: BoxDecoration(              shape: BoxShape.circle,              gradient: RadialGradient(                colors: [                  const Color(0xFF4CAF50).withOpacity(0.18),                  Colors.transparent,                ],              ),            ),          ),        ),        // Bottom-right glow        Positioned(          bottom: -100,          right: -80,          child: Container(            width: 320,            height: 320,            decoration: BoxDecoration(              shape: BoxShape.circle,              gradient: RadialGradient(                colors: [                  const Color(0xFF2E7D32).withOpacity(0.14),                  Colors.transparent,                ],              ),            ),          ),        ),      ],    );  }  /* ── TOP BAR ── */  Widget _topBar() {    return Padding(      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 12),      child: Row(        children: [          IconButton(            icon: Container(              padding: const EdgeInsets.all(8),              decoration: BoxDecoration(                color: const Color(0xFF1C1C2E),                borderRadius: BorderRadius.circular(12),                border: Border.all(color: const Color(0xFF2A2A3E)),              ),              child: const Icon(                Icons.arrow_back_ios_new_rounded,                color: Colors.white,                size: 16,              ),            ),            onPressed: () => Navigator.pop(context),          ),        ],      ),    );  }  /* ── HEADER ── */  Widget _headerSection() {    return Column(      children: [        // Animated shield icon        AnimatedBuilder(          animation: _pulseAnim,          builder: (_, __) => Transform.scale(            scale: _pulseAnim.value,            child: Container(              width: 88,              height: 88,              decoration: BoxDecoration(                shape: BoxShape.circle,                gradient: const LinearGradient(                  colors: [Color(0xFF43A047), Color(0xFF1B5E20)],                  begin: Alignment.topLeft,                  end: Alignment.bottomRight,                ),                boxShadow: [                  BoxShadow(                    color: const Color(0xFF4CAF50).withOpacity(0.35),                    blurRadius: 24,                    spreadRadius: 4,                  ),                ],              ),              child: const Icon(                Icons.shield_rounded,                color: Colors.white,                size: 44,              ),            ),          ),        ),        const SizedBox(height: 28),        const Text(          "Verification Code",          style: TextStyle(            color: Colors.white,            fontSize: 26,            fontWeight: FontWeight.w700,            letterSpacing: -0.5,          ),        ),        const SizedBox(height: 10),        RichText(          textAlign: TextAlign.center,          text: TextSpan(            style: const TextStyle(              color: Color(0xFF8888AA),              fontSize: 14.5,              height: 1.5,            ),            children: [              const TextSpan(text: "We sent a 6-digit code to\n"),              TextSpan(                text: widget.email,                style: const TextStyle(                  color: Color(0xFF66BB6A),                  fontWeight: FontWeight.w600,                ),              ),            ],          ),        ),      ],    );  }  /* ── OTP BOXES ── */  Widget _otpInputRow() {    return AnimatedBuilder(      animation: _shakeAnim,      builder: (_, child) {        final offset = _shakeError            ? (8 * (_shakeAnim.value < 0.5            ? _shakeAnim.value * 2            : (1 - _shakeAnim.value) * 2) *            (_shakeAnim.value < 0.25 || (_shakeAnim.value >= 0.5 && _shakeAnim.value < 0.75)                ? 1                : -1))            : 0.0;        return Transform.translate(          offset: Offset(offset, 0),          child: child,        );      },      child: Row(        mainAxisAlignment: MainAxisAlignment.spaceBetween,        children: List.generate(6, _buildOTPBox),      ),    );  }  Widget _buildOTPBox(int index) {    final isFocused = _focusNodes[index].hasFocus;    final hasValue = _controllers[index].text.isNotEmpty;    return SizedBox(      width: 48,      height: 60,      child: RawKeyboardListener(        focusNode: FocusNode(),        onKey: (event) => _onKeyPress(index, event),        child: AnimatedContainer(          duration: const Duration(milliseconds: 200),          decoration: BoxDecoration(            color: hasValue                ? const Color(0xFF1A2E1A)                : const Color(0xFF161625),            borderRadius: BorderRadius.circular(14),            border: Border.all(              color: _shakeError                  ? const Color(0xFFEF5350)                  : isFocused                  ? const Color(0xFF66BB6A)                  : hasValue                  ? const Color(0xFF388E3C)                  : const Color(0xFF2A2A3E),              width: isFocused || _shakeError ? 2 : 1.5,            ),            boxShadow: isFocused                ? [              BoxShadow(                color: const Color(0xFF4CAF50).withOpacity(0.25),                blurRadius: 12,                spreadRadius: 1,              ),            ]                : [],          ),          child: TextField(            controller: _controllers[index],            focusNode: _focusNodes[index],            keyboardType: TextInputType.number,            textAlign: TextAlign.center,            maxLength: index == 0 ? 6 : 1, // allow paste on first box            inputFormatters: [FilteringTextInputFormatter.digitsOnly],            style: TextStyle(              fontSize: 22,              fontWeight: FontWeight.w700,              color: hasValue ? const Color(0xFF81C784) : Colors.white,              letterSpacing: 0,            ),            decoration: const InputDecoration(              counterText: "",              border: InputBorder.none,              enabledBorder: InputBorder.none,              focusedBorder: InputBorder.none,            ),            onChanged: (val) => _onChanged(index, val),            onTap: () => setState(() {}),          ),        ),      ),    );  }  /* ── RESEND ── */  Widget _resendSection() {    return Column(      children: [        if (!canResend) ...[          Row(            mainAxisAlignment: MainAxisAlignment.center,            children: [              const Text(                "Resend code in  ",                style: TextStyle(color: Color(0xFF8888AA), fontSize: 14),              ),              Container(                padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),                decoration: BoxDecoration(                  color: const Color(0xFF1A2A1A),                  borderRadius: BorderRadius.circular(8),                  border: Border.all(color: const Color(0xFF2E5030)),                ),                child: Text(                  "${seconds}s",                  style: const TextStyle(                    color: Color(0xFF66BB6A),                    fontSize: 13,                    fontWeight: FontWeight.w600,                  ),                ),              ),            ],          ),          const SizedBox(height: 8),          // countdown bar          ClipRRect(            borderRadius: BorderRadius.circular(4),            child: TweenAnimationBuilder<double>(              tween: Tween(begin: 1.0, end: 0.0),              duration: const Duration(seconds: 30),              builder: (_, val, __) => LinearProgressIndicator(                value: seconds / 30,                backgroundColor: const Color(0xFF1C1C2E),                valueColor: const AlwaysStoppedAnimation(Color(0xFF43A047)),                minHeight: 3,              ),            ),          ),        ] else          GestureDetector(            onTap: resendOTP,            child: Container(              padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 10),              decoration: BoxDecoration(                color: const Color(0xFF1A2A1A),                borderRadius: BorderRadius.circular(12),                border: Border.all(color: const Color(0xFF388E3C)),              ),              child: Row(                mainAxisSize: MainAxisSize.min,                children: const [                  Icon(Icons.refresh_rounded, color: Color(0xFF66BB6A), size: 18),                  SizedBox(width: 8),                  Text(                    "Resend Code",                    style: TextStyle(                      color: Color(0xFF66BB6A),                      fontWeight: FontWeight.w600,                      fontSize: 14.5,                    ),                  ),                ],              ),            ),          ),      ],    );  }  /* ── VERIFY BUTTON ── */  Widget _verifyButton() {    final allFilled = _otpValue.length == 6;    return Column(      children: [        GestureDetector(          onTap: loading ? null : verifyOTP,          child: AnimatedContainer(            duration: const Duration(milliseconds: 200),            width: double.infinity,            height: 58,            decoration: BoxDecoration(              borderRadius: BorderRadius.circular(18),              gradient: allFilled                  ? const LinearGradient(                colors: [Color(0xFF43A047), Color(0xFF1B5E20)],                begin: Alignment.topLeft,                end: Alignment.bottomRight,              )                  : null,              color: allFilled ? null : const Color(0xFF1C1C2E),              boxShadow: allFilled                  ? [                BoxShadow(                  color: const Color(0xFF4CAF50).withOpacity(0.4),                  blurRadius: 20,                  offset: const Offset(0, 8),                ),              ]                  : [],              border: allFilled                  ? null                  : Border.all(color: const Color(0xFF2A2A3E)),            ),            child: loading                ? const Center(              child: SizedBox(                width: 24,                height: 24,                child: CircularProgressIndicator(                  color: Colors.white,                  strokeWidth: 2.5,                ),              ),            )                : Row(              mainAxisAlignment: MainAxisAlignment.center,              children: [                Text(                  "Verify & Continue",                  style: TextStyle(                    color: allFilled ? Colors.white : const Color(0xFF555570),                    fontSize: 16,                    fontWeight: FontWeight.w700,                    letterSpacing: 0.4,                  ),                ),                if (allFilled) ...[                  const SizedBox(width: 8),                  const Icon(                    Icons.arrow_forward_rounded,                    color: Colors.white,                    size: 20,                  ),                ]              ],            ),          ),        ),        const SizedBox(height: 24),        // Security note        Row(          mainAxisAlignment: MainAxisAlignment.center,          children: const [            Icon(Icons.lock_outline_rounded, size: 13, color: Color(0xFF555570)),            SizedBox(width: 5),            Text(              "Secured with end-to-end encryption",              style: TextStyle(                color: Color(0xFF555570),                fontSize: 12,              ),            ),          ],        ),      ],    );  }}